async def stop(self) -> None:
    if self._runner:
        await self._runner.cleanup()

async def _handle_manifest(self, request: web.Request) -> web.Response:
    entries = self._sentinel.manifest.all_entries()
    data = {k: v.model_dump() for k, v in entries.items()}
    return web.json_response({"components": data})

async def _handle_fix_detail(self, request: web.Request) -> web.Response:
    fix_id = request.match_info["fix_id"]
    for fix in self._sentinel.fixes:
        if fix.id == fix_id:
            return web.json_response(fix.model_dump())
    return web.json_response({"error": "Fix not found"}, status=404)

async def _handle_manual_fix(self, request: web.Request) -> web.Response:
    try:
        body = await request.json()
    except Exception:
        return web.json_response({"error": "Invalid JSON"}, status=400)

    pact_key = body.get("pact_key", "")
    error = body.get("error", "")
    if not pact_key or not error:
        return web.json_response(
            {"error": "pact_key and error required"}, status=400,
        )

    result = await self._sentinel.handle_manual_fix(pact_key, error)
    return web.json_response(result.model_dump())

async def _handle_register(self, request: web.Request) -> web.Response:
    try:
        body = await request.json()
    except Exception:
        return web.json_response({"error": "Invalid JSON"}, status=400)

    component_id = body.get("component_id", "")
    if not component_id:
        return web.json_response(
            {"error": "component_id required"}, status=400,
        )

    entry = ManifestEntry(
        component_id=component_id,
        contract_path=body.get("contract_path", ""),
        test_path=body.get("test_path", ""),
        source_path=body.get("source_path", ""),
        language=body.get("language", "python"),
        pact_project=body.get("pact_project", ""),
    )
    self._sentinel.manifest.register(entry)
    return web.json_response({"status": "registered", "component_id": component_id})

def __init__(self, config: ArbiterConfig) -> None:
    self._endpoint = config.api_endpoint
    self._trust_on_fix = config.trust_event_on_fix

async def report_fix_success(self, component_id: str, run_id: str = "") -> bool:
    """Report a successful fix (trust boost)."""
    if not self._trust_on_fix:
        return False
    return await self.report_trust_event(
        node_id=component_id,
        event="sentinel_fix",
        weight=1.5,
        run_id=run_id,
    )

async def report_fix_failure(self, component_id: str, run_id: str = "") -> bool:
    """Report a failed fix (trust penalty)."""
    if not self._trust_on_fix:
        return False
    return await self.report_trust_event(
        node_id=component_id,
        event="sentinel_fix_failure",
        weight=-0.5,
        run_id=run_id,
    )

def __init__(
    self,
    manifest: ManifestManager,
    key_pattern: str = r"PACT:[a-zA-Z0-9_]+:[a-zA-Z0-9_]+",
) -> None:
    self._manifest = manifest
    # Ensure pattern has capture groups; if user-provided pattern lacks them,
    # use it only for detection and fall back to default for extraction.
    compiled = re.compile(key_pattern)
    if compiled.groups >= 2:
        self._pattern = compiled
    else:
        self._pattern = self._DEFAULT_PATTERN

def extract_key(self, line: str) -> LogKey | None:
    """Extract a PACT key from a log line. Returns None if no match."""
    m = self._pattern.search(line)
    if not m:
        return None
    return LogKey(
        component_id=m.group(1),
        method_name=m.group(2) if m.lastindex and m.lastindex >= 2 else "",
        raw=m.group(0),
    )

def attribute_signal(self, signal: Signal) -> Attribution:
    """Attribute a Signal object. Checks log_key field first, then raw_text."""
    if signal.log_key:
        attr = self.attribute(signal.log_key)
        if attr.status != "unattributed":
            attr.error_context = signal.raw_text
            return attr
    return self.attribute(signal.raw_text)

def watch(ctx: click.Context) -> None:
    """Start watching configured log sources (long-running) (FA-S-003)."""
    config = ctx.obj["config"]
    if not config.sources:
        click.echo("No sources configured in sentinel.yaml. Add sources and retry.", err=True)
        sys.exit(1)

    from sentinel.sentinel import Sentinel

    sentinel = Sentinel(config)
    try:
        asyncio.run(sentinel.run())
    except KeyboardInterrupt:
        sentinel.stop()
        click.echo("\nSentinel stopped.")

async def _run():
    await sentinel.startup()
    return await sentinel.handle_manual_fix(pact_key, error)

def load_config(path: Path | None = None) -> SentinelConfig:
    """Load sentinel.yaml from the given path, cwd, or defaults.

    Search order: explicit path, ./sentinel.yaml, ~/.sentinel/sentinel.yaml.
    Returns default config if no file found.
    """
    candidates = []
    if path:
        candidates.append(path)
    candidates.extend([
        Path.cwd() / "sentinel.yaml",
        Path.home() / ".sentinel" / "sentinel.yaml",
    ])

    for candidate in candidates:
        if candidate.exists():
            try:
                data = yaml.safe_load(candidate.read_text()) or {}
                return SentinelConfig.model_validate(data)
            except Exception as e:
                logger.warning("Failed to load %s: %s", candidate, e)

    return SentinelConfig()

async def push_contract(self, proposal: ContractProposal) -> bool:
    """Push a tightened contract to Pact.

    If Pact project_dir is configured: calls `pact sentinel push-contract` via subprocess.
    If only api_endpoint: POSTs to the Pact API.
    If neither: writes to .sentinel/proposed_contracts/ with a warning (FA-S-016).
    """
    if not proposal.proposed_yaml.strip() or proposal.proposed_yaml.strip() == "none":
        return False

    if self._project_dir:
        return await self._push_via_cli(proposal)

    if self._api_endpoint:
        return await self._push_via_api(proposal)

    return self._write_proposal(proposal)

async def _push_via_api(self, proposal: ContractProposal) -> bool:
    """Push via Pact API endpoint."""
    import aiohttp

    try:
        async with aiohttp.ClientSession() as session:
            async with session.post(
                f"{self._api_endpoint}/contracts/{proposal.component_id}",
                json={
                    "component_id": proposal.component_id,
                    "contract_yaml": proposal.proposed_yaml,
                    "reason": proposal.reason,
                },
                timeout=aiohttp.ClientTimeout(total=10),
            ) as resp:
                if resp.status < 300:
                    return True
                logger.warning("Pact API returned %d", resp.status)
                return False
    except Exception as e:
        logger.warning("Pact API push failed: %s", e)
        return self._write_proposal(proposal)

def list_proposals(self) -> list[ContractProposal]:
    """List all locally stored contract proposals."""
    proposals = []
    if not self._proposals_dir.exists():
        return proposals
    for path in sorted(self._proposals_dir.glob("*.yaml")):
        proposals.append(ContractProposal(
            component_id=path.stem,
            proposed_yaml=path.read_text(),
        ))
    return proposals

def on(self, kind: str, handler: Callable) -> None:
    """Register a handler for an event kind."""
    self._handlers.setdefault(kind, []).append(handler)

async def emit(self, event: SentinelEvent) -> None:
    """Dispatch event to all registered handlers for its kind."""
    for handler in self._handlers.get(event.kind, []):
        try:
            result = handler(event)
            if hasattr(result, "__await__"):
                await result
        except Exception as e:
            logger.debug("Event handler error for %s: %s", event.kind, e)

    # Also dispatch to wildcard handlers
    for handler in self._handlers.get("*", []):
        try:
            result = handler(event)
            if hasattr(result, "__await__"):
                await result
        except Exception as e:
            logger.debug("Wildcard handler error: %s", e)

def build_narrative_debrief(
    attempt: int,
    prior_failures: list[str],
    last_test_results: TestResults | None,
) -> str:
    """Build enriched context for retry attempts."""
    if attempt <= 1:
        return ""

    sections = []
    sections.append(f"## ATTEMPT {attempt - 1} DEBRIEF")

    if prior_failures:
        capped = prior_failures[:10]
        for f in capped:
            truncated = f[:200] if len(f) > 200 else f
            sections.append(f"- {truncated}")
        if len(prior_failures) > 10:
            sections.append(f"... and {len(prior_failures) - 10} more failures")

    sections.append("")
    sections.append("## WHAT WENT WRONG")
    if last_test_results and last_test_results.failure_details:
        for fd in last_test_results.failure_details[:10]:
            sections.append(f"- {fd.test_id}: {fd.error_message}")
    elif prior_failures:
        sections.append("See failure list above.")
    else:
        sections.append("Previous attempt did not produce passing tests.")

    sections.append("")
    sections.append("## FRESH APPROACH REQUIRED")
    sections.append(
        "You are a senior engineer brought in specifically because the previous "
        "approach failed. Take a fundamentally different approach."
    )

    return "\n".join(sections)

def _extract_section(response: str, section_name: str) -> str:
    """Extract content between ### SECTION_NAME and the next ### or end of text."""
    marker = f"### {section_name}"
    idx = response.find(marker)
    if idx == -1:
        return ""

    start = idx + len(marker)
    # Skip any trailing whitespace/newlines after the header
    while start < len(response) and response[start] in (" ", "\t", "\n", "\r"):
        start += 1

    # Find next ### section header
    next_header = response.find("\n###", start)
    if next_header == -1:
        content = response[start:]
    else:
        content = response[start:next_header]

    # Strip markdown code fences if present
    content = content.strip()
    if content.startswith("```"):
        first_newline = content.find("\n")
        if first_newline != -1:
            content = content[first_newline + 1:]
    if content.endswith("```"):
        content = content[:-3]

    return content.strip()

def _read_file(path: str) -> str:
    """Read a file or directory's main content. Returns empty string on failure."""
    if not path:
        return ""
    p = Path(path)
    if p.is_file():
        try:
            return p.read_text()
        except Exception:
            return ""
    if p.is_dir():
        # Try common entry points
        for name in [f"{p.name}.py", "main.py", "__init__.py", "index.ts", "index.js"]:
            candidate = p / name
            if candidate.exists():
                try:
                    return candidate.read_text()
                except Exception:
                    pass
        # Read all .py files concatenated
        texts = []
        for py_file in sorted(p.glob("*.py")):
            try:
                texts.append(f"# --- {py_file.name} ---\n{py_file.read_text()}")
            except Exception:
                pass
        return "\n\n".join(texts)
    return ""

def __init__(self, repo_dir: Path) -> None:
    self._repo_dir = repo_dir
    self._is_git: bool | None = None

def is_git_repo(self) -> bool:
    """Check if repo_dir is inside a git repository."""
    if self._is_git is None:
        self._is_git = (self._repo_dir / ".git").exists() or any(
            (p / ".git").exists() for p in self._repo_dir.parents
        )
    return self._is_git

async def snapshot(self, message: str) -> str | None:
    """Commit all current changes as a snapshot. Returns commit hash or None."""
    if not self.is_git_repo:
        return None
    try:
        await self._run("add", "-A")
        rc, _, stderr = await self._run("commit", "-m", message, "--allow-empty")
        if rc != 0:
            logger.debug("Git snapshot commit failed: %s", stderr)
            return None
        return await self.current_hash()
    except Exception as e:
        logger.debug("Git snapshot failed: %s", e)
        return None

async def commit_fix(self, message: str, files: list[Path]) -> str | None:
    """Stage specific files and commit. Returns commit hash or None."""
    if not self.is_git_repo:
        return None
    try:
        for f in files:
            await self._run("add", str(f))
        rc, _, stderr = await self._run("commit", "-m", message)
        if rc != 0:
            logger.debug("Git commit failed: %s", stderr)
            return None
        return await self.current_hash()
    except Exception as e:
        logger.debug("Git commit failed: %s", e)
        return None

async def revert_to(self, commit_hash: str) -> bool:
    """Hard reset to a previous commit. Returns success."""
    if not self.is_git_repo:
        return False
    try:
        rc, _, stderr = await self._run("reset", "--hard", commit_hash)
        if rc != 0:
            logger.debug("Git revert failed: %s", stderr)
            return False
        return True
    except Exception as e:
        logger.debug("Git revert failed: %s", e)
        return False

def get_incident(self, incident_id: str) -> Incident | None:
    """Get an incident by ID."""
    return self._incidents.get(incident_id)

def get_active_incidents(self) -> list[Incident]:
    """Get all non-resolved, non-escalated incidents."""
    return [
        i for i in self._incidents.values()
        if i.status not in ("resolved", "escalated")
    ]

def record_spend(self, incident_id: str, amount: float) -> None:
    """Record spending against an incident."""
    incident = self._incidents.get(incident_id)
    if incident:
        incident.spend_usd += amount
        incident.updated_at = datetime.now().isoformat()
        self._spend_log.append({
            "timestamp": datetime.now().isoformat(),
            "incident_id": incident_id,
            "amount": amount,
        })
        self.save_state()

def _spend_in_window(self, start: datetime, end: datetime) -> float:
    """Sum all spending within a time window."""
    total = 0.0
    for entry in self._spend_log:
        ts = datetime.fromisoformat(entry["timestamp"])
        if start <= ts <= end:
            total += entry["amount"]
    return total

def find_by_fingerprint(self, fp_hash: str) -> Incident | None:
    """Find an active incident matching a fingerprint hash."""
    for incident in self.get_active_incidents():
        if incident.fingerprint and incident.fingerprint.hash == fp_hash:
            return incident
    return None

def load_state(self) -> dict:
    """Load all incidents from disk."""
    incidents_path = self._monitoring_dir / "incidents.json"
    budget_path = self._monitoring_dir / "budget.json"

    if incidents_path.exists():
        try:
            data = json.loads(incidents_path.read_text())
            self._incidents = {
                k: Incident.model_validate(v)
                for k, v in data.get("incidents", {}).items()
            }
        except (json.JSONDecodeError, Exception) as e:
            logger.debug("Failed to load incidents: %s", e)

    if budget_path.exists():
        try:
            data = json.loads(budget_path.read_text())
            self._spend_log = data.get("spend_log", [])
        except (json.JSONDecodeError, Exception) as e:
            logger.debug("Failed to load budget state: %s", e)

    return {"incidents": len(self._incidents), "spend_entries": len(self._spend_log)}

def save_state(self) -> None:
    """Persist all state to disk."""
    incidents_path = self._monitoring_dir / "incidents.json"
    budget_path = self._monitoring_dir / "budget.json"

    incidents_data = {
        "incidents": {
            k: v.model_dump() for k, v in self._incidents.items()
        },
    }
    incidents_path.write_text(json.dumps(incidents_data, indent=2, default=str))

    budget_data = {
        "budget": self._budget.model_dump(),
        "spend_log": self._spend_log,
    }
    budget_path.write_text(json.dumps(budget_data, indent=2, default=str))

def _pydantic_to_tool_schema(schema: type[BaseModel]) -> dict:
    """Convert a pydantic model to an Anthropic tool schema."""
    json_schema = schema.model_json_schema()

    # Remove title/description from top level to avoid duplication
    properties = json_schema.get("properties", {})
    required = json_schema.get("required", [])

    return {
        "name": schema.__name__,
        "description": schema.__doc__ or f"Extract {schema.__name__}",
        "input_schema": {
            "type": "object",
            "properties": properties,
            "required": required,
        },
    }

def _get_client(self):
    """Lazy-init the Anthropic client."""
    if self._client is None:
        try:
            from anthropic import AsyncAnthropic
            self._client = AsyncAnthropic()
        except ImportError:
            raise RuntimeError(
                "anthropic package required for LLM features. "
                "Install with: pip install sentinel-monitor[llm]"
            )
    return self._client

def __init__(self, sentinel_dir: Path) -> None:
    self._sentinel_dir = sentinel_dir
    self._manifest_path = sentinel_dir / "manifest.json"
    self._entries: dict[str, ManifestEntry] = {}
    self.load()

def lookup(self, component_id: str) -> ManifestEntry | None:
    """Look up a component by ID."""
    return self._entries.get(component_id)

def lookup_by_key(self, pact_key: str) -> ManifestEntry | None:
    """Look up by full PACT key string (PACT:<component_id>:<method>)."""
    m = _PACT_KEY_RE.search(pact_key)
    if not m:
        return None
    component_id = m.group(1)
    entry = self._entries.get(component_id)
    if entry:
        return entry
    # Try second segment as component_id (secondary format)
    return self._entries.get(m.group(2))

def all_entries(self) -> dict[str, ManifestEntry]:
    """Return all registered components."""
    return dict(self._entries)

def save(self) -> None:
    """Persist manifest to disk."""
    self._sentinel_dir.mkdir(parents=True, exist_ok=True)
    data = {
        "components": {
            k: v.model_dump() for k, v in self._entries.items()
        }
    }
    self._manifest_path.write_text(json.dumps(data, indent=2, default=str))

def load(self) -> None:
    """Load manifest from disk. No-op if file doesn't exist."""
    if not self._manifest_path.exists():
        return
    try:
        data = json.loads(self._manifest_path.read_text())
        self._entries = {
            k: ManifestEntry.model_validate(v)
            for k, v in data.get("components", {}).items()
        }
    except Exception as e:
        logger.warning("Failed to load manifest: %s", e)

async def notify(self, event_type: str, payload: dict) -> bool:
    """Send notification if event_type is enabled. Returns True on success."""
    if not self.is_configured():
        return False

    if event_type == "error" and not self._on_error:
        return False
    if event_type == "fix" and not self._on_fix:
        return False
    if event_type == "contract_push" and not self._on_contract_push:
        return False

    envelope = {
        "event_type": event_type,
        "timestamp": datetime.now().isoformat(),
        "source": "sentinel",
        **payload,
    }

    return await self._post(self._url, envelope)

def _find_incident_by_fingerprint(self, fp_hash: str) -> Incident | None:
    for incident in self._incident_mgr.get_recent_incidents(100):
        if incident.fingerprint and incident.fingerprint.hash == fp_hash:
            return incident
    return None

def _mentions_gdpr_erasable(context: str) -> bool:
    """Check if the error context involves a gdpr_erasable field."""
    return bool(re.search(r"gdpr[_\s]?erasable", context, re.IGNORECASE))

def __init__(self, ledger_mappings: list[SeverityMapping] | None = None) -> None:
    self._overrides: list[tuple[re.Pattern, str, str]] = []
    if ledger_mappings:
        for m in ledger_mappings:
            try:
                pattern = re.compile(m.field_pattern, re.IGNORECASE)
                self._overrides.append((pattern, m.annotation, m.sentinel_severity))
            except re.error:
                logger.warning("Invalid field_pattern in Ledger mapping: %s", m.field_pattern)

