async def triage_signal(
    llm: LLMClient,
    signal: Signal,
    manifest: ManifestManager,
) -> str | None:
    """Use LLM to map an error signal to a component ID.

    Returns component_id or None if can't be determined.
    """
    entries = manifest.all_entries()
    if not entries:
        return None

    # Build compact summary of all components
    summaries = []
    for comp_id, entry in entries.items():
        contract_text = ""
        if entry.contract_path:
            try:
                data = json.loads(open(entry.contract_path).read())
                funcs = [f.get("name", "") for f in data.get("functions", [])]
                types = [t.get("name", "") for t in data.get("types", [])]
                contract_text = f"functions=[{', '.join(funcs)}], types=[{', '.join(types)}]"
            except Exception:
                contract_text = "(contract unreadable)"
        summaries.append(f"- {comp_id}: {contract_text}")

    components_text = "\n".join(summaries)

    prompt = f"""Error signal from production:
Source: {signal.source}
Raw text: {signal.raw_text}
File: {signal.file_path}
Process: {signal.process_name}

Known components:
{components_text}

Which component most likely produced this error?"""

    try:
        result, _, _ = await llm.assess(
            TriageResult, prompt, TRIAGE_SYSTEM, max_tokens=1024,
        )
        if result.component_id == "unknown" or result.confidence < 0.3:
            return None
        if result.component_id in entries:
            return result.component_id
        return None
    except Exception as e:
        logger.debug("Triage failed: %s", e)
        return None

async def generate_diagnostic_report(
    llm: LLMClient,
    incident_id: str,
    signal: Signal,
    manifest: ManifestManager,
    component_id: str = "",
    attempted_fixes: list[str] | None = None,
) -> DiagnosticResult | None:
    """Generate a diagnostic report for escalation."""
    context = ""
    if component_id:
        entry = manifest.lookup(component_id)
        if entry and entry.contract_path:
            try:
                context = open(entry.contract_path).read()[:2000]
            except Exception:
                context = "(contract unreadable)"

    fixes_text = "\n".join(f"  {i}. {f}" for i, f in enumerate(attempted_fixes or [], 1)) or "None"

    prompt = f"""Analyze this production incident.

Incident ID: {incident_id}
Component: {component_id or 'unknown'}

Error:
  [{signal.source}] {signal.raw_text[:500]}

Contract context:
{context or 'No contract available'}

Attempted fixes:
{fixes_text}

Produce a diagnostic report."""

    try:
        result, _, _ = await llm.assess(
            DiagnosticResult, prompt,
            "Analyze the incident and produce a diagnostic report.",
            max_tokens=2048,
        )
        return result
    except Exception as e:
        logger.debug("Diagnostic report generation failed: %s", e)
        return None

def stop(self) -> None:
    self._stopped = True
    if self._process:
        self._process.terminate()

async def watch(self):
    while True:
        for pattern in self.patterns:
            try:
                proc = await asyncio.create_subprocess_exec(
                    "pgrep", "-f", pattern,
                    stdout=asyncio.subprocess.PIPE,
                    stderr=asyncio.subprocess.DEVNULL,
                )
                stdout, _ = await proc.communicate()
                current_pids = set(stdout.decode().strip().split("\n")) - {""}
                lost = self._known_pids - current_pids
                if self._known_pids and lost:
                    yield Signal(
                        source="process",
                        raw_text=f"Process matching '{pattern}' disappeared (PIDs: {', '.join(lost)})",
                        timestamp=datetime.now().isoformat(),
                        process_name=pattern,
                    )
                self._known_pids = current_pids
            except Exception:
                pass
        await asyncio.sleep(self.poll_interval)

async def _handle_connection(
    self,
    reader: asyncio.StreamReader,
    writer: asyncio.StreamWriter,
) -> None:
    try:
        await reader.readline()  # request line
        headers: dict[str, str] = {}
        while True:
            header_line = await reader.readline()
            if header_line in (b"\r\n", b"\n", b""):
                break
            if b":" in header_line:
                key, val = header_line.decode().split(":", 1)
                headers[key.strip().lower()] = val.strip()

        content_length = int(headers.get("content-length", "0"))
        body = b""
        if content_length > 0:
            body = await reader.readexactly(content_length)

        try:
            data = json.loads(body.decode())
            signal = Signal(
                source="webhook",
                raw_text=data.get("error", data.get("message", str(data))),
                timestamp=datetime.now().isoformat(),
                log_key=data.get("log_key", ""),
            )
            await self._queue.put(signal)
            response = b"HTTP/1.1 200 OK\r\nContent-Length: 2\r\n\r\nOK"
        except (json.JSONDecodeError, KeyError):
            response = b"HTTP/1.1 400 Bad Request\r\nContent-Length: 11\r\n\r\nBad Request"

        writer.write(response)
        await writer.drain()
    except Exception:
        pass
    finally:
        writer.close()
        try:
            await writer.wait_closed()
        except Exception:
            pass

def stop(self) -> None:
    if self._server:
        self._server.close()

def _get_client(self):
    """Lazy-init the boto3 CloudWatch Logs client."""
    if self._client is None:
        try:
            import boto3
        except ImportError:
            raise RuntimeError(
                "boto3 package required for CloudWatch source. "
                "Install with: pip install sentinel-monitor[cloudwatch]"
            )
        kwargs: dict = {"service_name": "logs"}
        if self.region:
            kwargs["region_name"] = self.region
        self._client = boto3.client(**kwargs)
    return self._client

async def signals(self):
    """Async generator yielding Signal objects from CloudWatch Logs."""
    import time

    if self._last_timestamp == 0:
        # Start from 5 minutes ago to avoid huge initial fetch
        self._last_timestamp = int((time.time() - 300) * 1000)

    while not self._stopped:
        try:
            client = self._get_client()
            kwargs: dict = {
                "logGroupName": self.log_group,
                "startTime": self._last_timestamp + 1,
                "interleaved": True,
            }
            if self.filter_pattern:
                kwargs["filterPattern"] = self.filter_pattern

            # Run the blocking boto3 call in a thread executor
            loop = asyncio.get_event_loop()
            response = await loop.run_in_executor(
                None, lambda: client.filter_log_events(**kwargs)
            )

            events = response.get("events", [])
            for event in events:
                message = event.get("message", "").rstrip()
                ts = event.get("timestamp", 0)

                if ts > self._last_timestamp:
                    self._last_timestamp = ts

                # Apply error patterns if no CloudWatch filter_pattern
                if not self.filter_pattern:
                    if not any(p.search(message) for p in self._patterns):
                        continue

                yield Signal(
                    source="log_file",
                    raw_text=message,
                    timestamp=datetime.fromtimestamp(ts / 1000).isoformat() if ts else datetime.now().isoformat(),
                    file_path=self.log_group,
                    log_key=_extract_key_str(message),
                )

        except RuntimeError:
            # boto3 not installed — re-raise immediately
            raise
        except Exception as e:
            logger.warning("CloudWatch poll error for %s: %s", self.log_group, e)

        await asyncio.sleep(self.poll_interval)

async def watch_process(self, proc: asyncio.subprocess.Process):
    """Yield signals from a process's stdout."""
    if not proc.stdout:
        return
    while True:
        try:
            line_bytes = await proc.stdout.readline()
            if not line_bytes:
                break
            line = line_bytes.decode("utf-8", errors="replace").rstrip()
            if any(p.search(line) for p in self._patterns):
                yield Signal(
                    source="log_file",
                    raw_text=line,
                    timestamp=datetime.now().isoformat(),
                )
        except asyncio.CancelledError:
            break

async def _consume_cloudwatch(self, cw: CloudWatchSource) -> None:
    try:
        async for signal in cw.signals():
            if self._deduplicate(signal):
                await self._signal_queue.put(signal)
    except asyncio.CancelledError:
        pass

async def _consume_webhook(self, wh: WebhookReceiver) -> None:
    try:
        async for signal in wh.signals():
            if self._deduplicate(signal):
                await self._signal_queue.put(signal)
    except asyncio.CancelledError:
        pass

def stop(self) -> None:
    for task in self._tasks:
        task.cancel()
    for tailer in self._tailers:
        tailer.stop()
    for webhook in self._webhooks:
        webhook.stop()
    for cw in self._cloudwatch_sources:
        cw.stop()
